1	namespace TradeBlotter.Api.Domain;
2	
3	/// <summary>
4	/// Derives net positions and average cost per symbol from a trade history.
5	///
6	/// The average-cost method (with reset on sign flip) works as follows, replaying a
7	/// symbol's trades oldest-to-newest while tracking a signed net quantity and an
8	/// average cost. Let <c>signed</c> be the incoming trade's signed quantity:
9	///
10	///   1. Opening from flat (net == 0): net = signed; avg = price.
11	///   2. Increasing exposure (net and signed share a sign): weighted-average the new
12	///      fill in — avg = (avg*|net| + price*|signed|) / (|net| + |signed|); net += signed.
13	///   3. Reducing exposure without crossing zero (opposite signs, |signed| <= |net|):
14	///      net += signed; avg is UNCHANGED (the closed portion realizes P&L, which the
15	///      open position's average cost does not reflect). If net hits exactly 0, the
16	///      symbol is flat.
17	///   4. Flipping through zero (opposite signs, |signed| > |net|): the trade fully
18	///      closes the old side and opens a new one on the other side; net += signed and
19	///      avg RESETS to the flipping trade's price (the residual lot was acquired there).
20	///
21	/// Symbols with a net quantity of zero are omitted from the result.
22	/// </summary>
23	public static class PositionCalculator
24	{
25	    public static IReadOnlyList<Position> Derive(IEnumerable<Trade> trades)
26	    {
27	        var positions = new List<Position>();
28	
29	        // Group by symbol, then replay each symbol's trades in chronological order.
30	        var bySymbol = trades
31	            .GroupBy(t => t.Symbol, StringComparer.OrdinalIgnoreCase)
32	            .OrderBy(g => g.Key, StringComparer.Ordinal);
33	
34	        foreach (var group in bySymbol)
35	        {
36	            decimal net = 0m;
37	            decimal avg = 0m;
38	
39	            foreach (var trade in group.OrderBy(t => t.Timestamp))
40	            {
41	                var signed = trade.SignedQuantity;
42	                var price = trade.Price;
43	
44	                if (net == 0m)
45	                {
46	                    // Rule 1: opening from flat.
47	                    net = signed;
48	                    avg = price;
49	                }
50	                else if (Math.Sign(net) == Math.Sign(signed))
51	                {
52	                    // Rule 2: increasing exposure — weighted-average the new fill in.
53	                    var absNet = Math.Abs(net);
54	                    var absSigned = Math.Abs(signed);
55	                    avg = (avg * absNet + price * absSigned) / (absNet + absSigned);
56	                    net += signed;
57	                }
58	                else if (Math.Abs(signed) <= Math.Abs(net))
59	                {
60	                    // Rule 3: reducing exposure without crossing zero — avg unchanged.
61	                    net += signed;
62	                    if (net == 0m)
63	                    {
64	                        avg = 0m;
65	                    }
66	                }
67	                else
68	                {
69	                    // Rule 4: flipping through zero — reset avg to this trade's price.
70	                    net += signed;
71	                    avg = price;
72	                }
73	            }
74	
75	            // Rule: omit flat symbols from the response.
76	            if (net != 0m)
77	            {
78	                positions.Add(new Position(group.Key, net, avg));
79	            }
80	        }
81	
82	        return positions;
83	    }
84	}
