19	/** Validate a numeric field that may arrive as a number, '', or a raw string. */
20	function validateNumber(raw: number | string, label: string): string | null {
21	  const text = String(raw ?? '').trim()
22	  if (text === '') return `${label} must be a number.`
23	  const value = Number(text)
24	  if (Number.isNaN(value)) return `${label} must be a number.`
25	  if (value <= 0) return `${label} must be positive.`
26	  return null
27	}
28	
29	function validate(): boolean {
30	  for (const key of Object.keys(errors)) delete errors[key]
31	
32	  if (!String(form.symbol).trim()) {
33	    errors.symbol = 'Symbol is required.'
34	  }
35	
36	  const qtyError = validateNumber(form.quantity, 'Quantity')
37	  if (qtyError) errors.quantity = qtyError
38	
39	  const priceError = validateNumber(form.price, 'Price')
40	  if (priceError) errors.price = priceError
41	
42	  return Object.keys(errors).length === 0
43	}
