2	import { computed, ref } from 'vue'
3	import { useBlotterStore } from '../stores/blotter'
4	import type { Trade } from '../types'
5	
6	const store = useBlotterStore()
7	
8	type SortKey = 'timestamp' | 'symbol' | 'quantity' | 'price' | 'notional'
9	type SortDir = 'asc' | 'desc'
10	
11	const sortKey = ref<SortKey>('timestamp')
12	const sortDir = ref<SortDir>('desc')
13	
14	function toggleSort(key: SortKey) {
15	  if (sortKey.value === key) {
16	    sortDir.value = sortDir.value === 'asc' ? 'desc' : 'asc'
17	  } else {
18	    sortKey.value = key
19	    sortDir.value = key === 'symbol' ? 'asc' : 'desc'
20	  }
21	}
22	
23	const sortedTrades = computed<Trade[]>(() => {
24	  const dir = sortDir.value === 'asc' ? 1 : -1
25	  return [...store.trades].sort((a, b) => {
26	    let cmp: number
27	    switch (sortKey.value) {
28	      case 'symbol':
29	        cmp = a.symbol.localeCompare(b.symbol)
30	        break
31	      case 'timestamp':
32	        cmp = new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
33	        break
34	      default:
35	        cmp = a[sortKey.value] - b[sortKey.value]
36	    }
37	    return cmp * dir
38	  })
39	})
40	
41	const currency = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' })
42	const qtyFmt = new Intl.NumberFormat('en-US', { maximumFractionDigits: 4 })
43	
44	function formatTime(iso: string): string {
45	  return new Date(iso).toLocaleString('en-US', {
46	    month: 'short',
47	    day: '2-digit',
48	    hour: '2-digit',
49	    minute: '2-digit',
50	    second: '2-digit',
51	    hour12: false,
52	  })
53	}
54	
55	function ariaSort(key: SortKey): 'ascending' | 'descending' | 'none' {
56	  if (sortKey.value !== key) return 'none'
57	  return sortDir.value === 'asc' ? 'ascending' : 'descending'
58	}
59	
60	function caret(key: SortKey): string {
61	  if (sortKey.value !== key) return ''
62	  return sortDir.value === 'asc' ? '▲' : '▼'
63	}
64	</script>
