#!/usr/bin/env python3
"""Convert a Claude Code session .jsonl transcript into a readable Markdown log.

Renders the conversation in order: user prompts, assistant replies, tool calls
(name + brief input), and tool results (truncated). Internal chain-of-thought
(`thinking`) blocks are omitted for readability; the raw .jsonl kept alongside
this file is the authoritative, complete export.
"""
import json, sys, re

TOOL_IN = 260      # truncate tool-call input
TOOL_OUT = 600     # truncate tool result
SR = re.compile(r"<system-reminder>.*?</system-reminder>", re.S)

def clean(t):
    t = SR.sub("[system-reminder omitted]", t or "")
    return t.strip()

def trunc(s, n):
    s = (s or "").strip().replace("\r", "")
    return s if len(s) <= n else s[:n].rstrip() + f" …[+{len(s)-n} chars]"

def tool_input_summary(inp):
    if not isinstance(inp, dict):
        return trunc(str(inp), TOOL_IN)
    # Prefer the most descriptive fields per tool.
    for k in ("command", "description", "prompt", "file_path", "path", "query", "content", "url", "pattern"):
        if k in inp and isinstance(inp[k], str) and inp[k].strip():
            return f"`{k}`: " + trunc(inp[k], TOOL_IN)
    return trunc(json.dumps(inp, ensure_ascii=False), TOOL_IN)

def main(path, out):
    rows = []
    with open(path) as f:
        for ln in f:
            try:
                rows.append(json.loads(ln))
            except Exception:
                pass
    md = []
    turn = 0
    for o in rows:
        if o.get("type") not in ("user", "assistant"):
            continue
        m = o.get("message")
        if not isinstance(m, dict):
            continue
        role = m.get("role")
        content = m.get("content")
        items = content if isinstance(content, list) else [{"type": "text", "text": content}]
        for it in items:
            if not isinstance(it, dict):
                continue
            t = it.get("type")
            if t == "text":
                txt = clean(it.get("text", ""))
                if not txt:
                    continue
                if role == "user":
                    turn += 1
                    md.append(f"\n---\n\n### 👤 User\n\n{txt}\n")
                else:
                    md.append(f"\n### 🤖 Claude\n\n{txt}\n")
            elif t == "tool_use" and role == "assistant":
                md.append(f"\n> 🔧 **{it.get('name','tool')}** — {tool_input_summary(it.get('input'))}\n")
            elif t == "tool_result" and role == "user":
                c = it.get("content")
                if isinstance(c, list):
                    c = "\n".join(x.get("text", "") for x in c if isinstance(x, dict))
                txt = clean(c if isinstance(c, str) else json.dumps(c, ensure_ascii=False))
                if txt:
                    md.append(f"\n<details><summary>tool result</summary>\n\n```\n{trunc(txt, TOOL_OUT)}\n```\n\n</details>\n")
    with open(out, "w") as f:
        f.write("".join(md).lstrip())
    print(f"wrote {out}: {len(md)} blocks, {turn} user turns")

if __name__ == "__main__":
    main(sys.argv[1], sys.argv[2])

